children.text:
.container {
  direction: rtl;
  width: 175px;
  line-height: 0;
}

.shape {
  float: right;
  shape-outside: content-box;
  box-sizing: content-box;
  height: 25px;
  width: 25px;
  padding: 25px;
  border: 25px solid lightgreen;
  margin: 25px;
  background-color: orange;
}

.box {
  display: inline-block;
  width: 50px;
  height: 25px;
  background-color: blue;
}

.longbox {
  display: inline-block;
  width: 175px;
  height: 25px;
  background-color: blue;
}
